app = Flask(__name__)
registry = CollectorRegistry()

# Dictionary to hold counters for each unique user-path combination
request_counters = {}

@app.route('/metrics')
def metrics():
    return generate_latest(registry)

@app.before_request
def track_requests():
    user_id = request.args.get('user_id', 'unknown')
    session_id = request.args.get('session_id', 'unknown')
